#!/usr/bin/env python3
"""
SOVEREIGN Bot v1.0
- AI Chat (DeepSeek via AiVene)
- Web Search (Tavily)
- Auto-detect kapan perlu search
- Chat history tersimpan
"""

import json
import os
import requests
from datetime import datetime
from pathlib import Path
from flask import Flask, request, jsonify, send_from_directory
from tavily import TavilyClient

# ═══════════════════════════════════════
# CONFIG
# ═══════════════════════════════════════
BASE_DIR = Path(__file__).parent
CONFIG = json.loads((BASE_DIR / 'config.json').read_text())
HISTORY_FILE = BASE_DIR / 'chat_history.json'

app = Flask(__name__, static_folder='static')

# Init Tavily
tavily = TavilyClient(api_key=CONFIG['search']['api_key'])

# Chat history (in-memory + file)
chat_history = []
if HISTORY_FILE.exists():
    try:
        chat_history = json.loads(HISTORY_FILE.read_text())
    except:
        chat_history = []


# ═══════════════════════════════════════
# SEARCH FUNCTION
# ═══════════════════════════════════════
def web_search(query, max_results=5):
    """Search Google via Tavily"""
    try:
        response = tavily.search(
            query=query,
            max_results=max_results,
            search_depth="advanced",
            include_answer=True
        )

        results = []
        if response.get('answer'):
            results.append(f"📌 **Jawaban singkat:** {response['answer']}")

        for i, r in enumerate(response.get('results', []), 1):
            title = r.get('title', 'Tanpa judul')
            url = r.get('url', '')
            content = r.get('content', '')[:500]
            results.append(f"**{i}. {title}**\n   🔗 {url}\n   {content}\n")

        return "\n".join(results) if results else "Gak ditemukan hasil search."
    except Exception as e:
        return f"❌ Error search: {str(e)}"


# ═══════════════════════════════════════
# AI FUNCTION (pakai requests, bukan urllib)
# ═══════════════════════════════════════
def ai_chat(messages, search_context=None):
    """Chat with AI via AiVene"""
    api_config = CONFIG['ai']

    # Tambahin search context ke messages kalau ada
    if search_context:
        search_msg = {
            "role": "system",
            "content": f"🔍 **Hasil Web Search:**\n\n{search_context}\n\nGunakan informasi di atas untuk menjawab pertanyaan user dengan akurat."
        }
        messages = list(messages)
        messages.insert(-1, search_msg)

    payload = {
        "model": api_config['model'],
        "messages": messages,
        "max_tokens": api_config['max_tokens'],
        "temperature": api_config['temperature'],
        "stream": False
    }

    try:
        resp = requests.post(
            f"{api_config['base_url']}/chat/completions",
            json=payload,
            headers={
                "Content-Type": "application/json",
                "Authorization": f"Bearer {api_config['api_key']}"
            },
            timeout=60
        )
        resp.raise_for_status()
        result = resp.json()
        return result['choices'][0]['message']['content']
    except requests.exceptions.HTTPError as e:
        try:
            error_data = e.response.json()
            return f"❌ AI Error: {error_data.get('error', {}).get('message', str(e))}"
        except:
            return f"❌ AI Error: HTTP {e.response.status_code}"
    except Exception as e:
        return f"❌ AI Error: {str(e)}"


# ═══════════════════════════════════════
# SEARCH INTENT DETECTION
# ═══════════════════════════════════════
SEARCH_KEYWORDS = [
    'harga', 'berita', 'terbaru', 'sekarang', 'hari ini', 'update',
    'kurs', 'cuaca', 'prediksi', 'trend', 'trending', 'populer',
    'siapa', 'apa itu', 'dimana', 'kapan', 'berapa', 'mengapa',
    'cara', 'tutorial', 'review', 'perbandingan', 'rekomendasi',
    'download', 'apk', 'aplikasi', 'situs', 'website',
    'btc', 'bitcoin', 'crypto', 'saham', 'ihsg',
    'olahraga', 'skor', 'livescore', 'jadwal',
    'film', 'movie', 'musik', 'lagu',
    'resep', 'makanan', 'tempat wisata',
    'lowongan', 'kerja', 'gaji',
    'price', 'news', 'today', 'latest', 'update',
    'weather', 'stock', 'crypto', 'bitcoin',
    'who', 'what', 'where', 'when', 'how', 'why',
    'best', 'top', 'review', 'comparison',
]

def needs_search(user_message):
    """Deteksi apakah user butuh search"""
    msg_lower = user_message.lower()

    # Force search dengan prefix
    if msg_lower.startswith('/') or msg_lower.startswith('!'):
        return True, user_message.lstrip('/!').strip()

    # Cek keywords
    for keyword in SEARCH_KEYWORDS:
        if keyword in msg_lower:
            return True, user_message

    # Pertanyaan langsung
    if user_message.strip().endswith('?'):
        return True, user_message

    return False, None


