@app.route('/')
def index():
    return send_from_directory('static', 'index.html')

@app.route('/<path:filename>')
def static_files(filename):
    return send_from_directory('static', filename)

@app.route('/api/chat', methods=['POST'])
def chat():
    global chat_history

    data = request.json
    user_message = data.get('message', '').strip()
    force_search = data.get('force_search', False)

    if not user_message:
        return jsonify({"error": "Message kosong"}), 400

    # Handle commands
    if user_message.lower() in ['/clear', '!clear']:
        clear_history()
        return jsonify({"reply": "✅ Chat history dihapus!", "search_used": False})

    if user_message.lower() in ['/info', '!info']:
        info = {
            "name": CONFIG['bot']['name'],
            "model": CONFIG['ai']['model'],
            "features": ["AI Chat", "Web Search (Tavily)", "Chat History"]
        }
        return jsonify({"reply": f"🤖 **{info['name']}**\n🧠 Model: {info['model']}\n🔍 Search: Tavily\n💬 Fitur: {', '.join(info['features'])}", "search_used": False})

    # Tambahin ke history
    chat_history.append({
        "role": "user",
        "content": user_message,
        "time": datetime.now().isoformat()
    })

    # Build messages untuk AI
    system_prompt = CONFIG['bot']['system_prompt']
    messages = [{"role": "system", "content": system_prompt}]

    # Tambahin chat history (max 10 terakhir)
    for h in chat_history[-10:]:
        messages.append({
            "role": h['role'],
            "content": h['content']
        })

    # Cek apakah perlu search
    should_search, search_query = needs_search(user_message)
    if force_search:
        should_search = True
        search_query = user_message

    search_context = None
    search_used = False
    search_results = ""

    if should_search and search_query:
        try:
            search_results = web_search(search_query, CONFIG['search']['max_results'])
            search_context = search_results
            search_used = True
        except Exception as e:
            search_results = f"⚠️ Search error: {str(e)}"

    # Chat with AI
    reply = ai_chat(messages, search_context)

    # Simpan ke history
    chat_history.append({
        "role": "assistant",
        "content": reply,
        "time": datetime.now().isoformat(),
        "search_used": search_used
    })

    # Simpan history ke file
    try:
        HISTORY_FILE.write_text(json.dumps(chat_history[-100:], indent=2, ensure_ascii=False))
    except:
        pass

    return jsonify({
        "reply": reply,
        "search_used": search_used,
        "search_results": search_results if search_used else None,
        "model": CONFIG['ai']['model'],
        "timestamp": datetime.now().isoformat()
    })

