// State
let chatHistory = [];
let currentChatId = Date.now().toString();
let conversationMessages = [];

// Token tracking
let tokenStats = {
    totalInput: 0,
    totalOutput: 0,
    totalTokens: 0,
    messageCount: 0,
    userTokens: 0,
    botTokens: 0,
    maxTokens: 100000  // Default limit display
};

// Load saved token stats
function loadTokenStats() {
    const saved = localStorage.getItem('sovereign_token_stats');
    if (saved) {
        tokenStats = { ...tokenStats, ...JSON.parse(saved) };
    }
    updateTokenDisplay();
}

function saveTokenStats() {
    localStorage.setItem('sovereign_token_stats', JSON.stringify(tokenStats));
}

// System prompt
const SYSTEM_PROMPT = `Kamu adalah SOVEREIGN, autonomous AI agent yang jalan di HP Android (Termux).
Kamu bisa ngobrol, coding, brainstorming, jelasin konsep, dll.
Jawab dalam Bahasa Indonesia santai, to the point, dan helpful.
Gunakan emoji sesekali. Kalau diminta bikin script/code, langsung kasih contohnya.`;

// DOM Elements
const chatContainer = document.getElementById('chatContainer');
const messagesContainer = document.getElementById('messages');
const welcomeScreen = document.getElementById('welcomeScreen');
const messageInput = document.getElementById('messageInput');
const sendBtn = document.getElementById('sendBtn');
const typingIndicator = document.getElementById('typingIndicator');

// Initialize
document.addEventListener('DOMContentLoaded', () => {
    loadChatHistory();
    loadTokenStats();
    messageInput.focus();
});

// Handle Enter Key
function handleKeyDown(e) {
    if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        sendMessage();
    }
}

// Auto Resize Textarea
function autoResize(textarea) {
    textarea.style.height = 'auto';
    textarea.style.height = Math.min(textarea.scrollHeight, 120) + 'px';
}

// Get Current Time
function getCurrentTime() {
    return new Date().toLocaleTimeString('id-ID', { 
        hour: '2-digit', 
        minute: '2-digit' 
    });
}

// Estimate tokens (rough: ~4 chars per token)
function estimateTokens(text) {
    return Math.ceil(text.length / 4);
}

// Format number with K/M suffix
function formatNumber(num) {
    if (num >= 1000000) return (num / 1000000).toFixed(1) + 'M';
    if (num >= 1000) return (num / 1000).toFixed(1) + 'K';
    return num.toString();
}

// ========== TOKEN DASHBOARD FUNCTIONS ==========

// Toggle token panel
function toggleTokenPanel() {
    const panel = document.getElementById('tokenPanel');
    const arrow = document.getElementById('tokenArrow');
    panel.classList.toggle('open');
    arrow.classList.toggle('open');
}

// Update ring chart
function updateRing(id, percentage) {
    const ring = document.getElementById(id);
    const circumference = 251.2;
    const offset = circumference - (Math.min(percentage, 100) / 100) * circumference;
    ring.style.strokeDashoffset = offset;
}

// Animate number change
function animateNumber(elementId, newValue) {
    const el = document.getElementById(elementId);
    if (el) {
        el.textContent = newValue;
        el.classList.remove('number-pop');
        void el.offsetWidth; // Trigger reflow
        el.classList.add('number-pop');
    }
}

// Update all token displays
function updateTokenDisplay() {
    const { totalInput, totalOutput, totalTokens, messageCount, userTokens, botTokens, maxTokens } = tokenStats;

    // Mini header display
    animateNumber('tokenTotalMini', formatNumber(totalTokens));

    // Ring numbers
    animateNumber('ringInputNum', formatNumber(totalInput));
    animateNumber('ringOutputNum', formatNumber(totalOutput));
    animateNumber('ringTotalNum', formatNumber(totalTokens));

    // Ring charts (percentage of maxTokens)
    const inputPct = (totalInput / maxTokens) * 100;
    const outputPct = (totalOutput / maxTokens) * 100;
    const totalPct = (totalTokens / maxTokens) * 100;

    updateRing('ringInput', inputPct);
    updateRing('ringOutput', outputPct);
    updateRing('ringTotal', totalPct);

    // Progress bar
    const usedPct = Math.min((totalTokens / maxTokens) * 100, 100);
    document.getElementById('tokenProgressBar').style.width = usedPct + '%';
    document.getElementById('progressUsed').textContent = formatNumber(totalTokens) + ' tokens';
    document.getElementById('progressLimit').textContent = '/' + formatNumber(maxTokens);
    document.getElementById('sessionStats').textContent = messageCount + ' pesan • ' + formatNumber(totalTokens) + ' token';

    // Stats grid
    animateNumber('statMessages', messageCount);
    animateNumber('statUserTokens', formatNumber(userTokens));
    animateNumber('statBotTokens', formatNumber(botTokens));

    const avgPerMsg = messageCount > 0 ? formatNumber(Math.round(totalTokens / messageCount)) : '0';
    document.getElementById('statAvgPerMsg').textContent = avgPerMsg;
}

// Reset token stats
function resetTokenStats() {
    tokenStats = {
        totalInput: 0,
        totalOutput: 0,
        totalTokens: 0,
        messageCount: 0,
        userTokens: 0,
        botTokens: 0,
        maxTokens: tokenStats.maxTokens
    };
    saveTokenStats();
    updateTokenDisplay();
}

// ========== MESSAGE FUNCTIONS ==========

// Create Message Element
function createMessageElement(text, sender) {
    const messageDiv = document.createElement('div');
    messageDiv.className = `message ${sender}`;

    const avatar = sender === 'user' ? '👤' : '⚡';
    const time = getCurrentTime();

    const formattedText = formatMessage(text);

    messageDiv.innerHTML = `
        <div class="message-avatar">${avatar}</div>
        <div class="message-content">
            <div class="message-bubble">${formattedText}</div>
            <span class="message-time">${time}</span>
        </div>
    `;

    return messageDiv;
}

// Format Message (markdown support)
function formatMessage(text) {
    text = text.replace(/```(\w+)?\n([\s\S]*?)```/g, '<pre><code>$2</code></pre>');
    text = text.replace(/```([\s\S]*?)```/g, '<pre><code>$1</code></pre>');
    text = text.replace(/`([^`]+)`/g, '<code>$1</code>');
    text = text.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
    text = text.replace(/\*([^*]+)\*/g, '<em>$1</em>');
    text = text.replace(/\n/g, '<br>');
    return text;
}

// Send Message
async function sendMessage(text = null) {
    const message = text || messageInput.value.trim();

    if (!message) return;

    welcomeScreen.classList.add('hidden');

    const userMessage = createMessageElement(message, 'user');
    messagesContainer.appendChild(userMessage);

    // Track user tokens
    const userTokenCount = estimateTokens(message);
    tokenStats.userTokens += userTokenCount;
    tokenStats.totalInput += userTokenCount;
    tokenStats.totalTokens += userTokenCount;

    chatHistory.push({
        role: 'user',
        content: message,
        time: getCurrentTime()
    });

    conversationMessages.push({
        role: 'user',
        content: message
    });

    messageInput.value = '';
    messageInput.style.height = 'auto';
    scrollToBottom();
    showTyping();

    await getAIResponse(message);
}

// Get AI Response from API
async function getAIResponse(userMessage) {
    try {
        const messagesToSend = conversationMessages.slice(-20);

        const response = await fetch('/api/chat', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                messages: messagesToSend,
                max_tokens: 2048,
                temperature: 0.7
            })
        });

        const data = await response.json();

        hideTyping();

        const reply = data.reply || 'Gak bisa generate response. Coba lagi.';

        const agentMessage = createMessageElement(reply, 'agent');
        messagesContainer.appendChild(agentMessage);

        // Track bot tokens
        const botTokenCount = estimateTokens(reply);
        const apiTokens = data.usage || {};

        // Use API token count if available, otherwise estimate
        const actualInput = apiTokens.prompt_tokens || userTokenCount || estimateTokens(messagesToSend.map(m => m.content).join(' '));
        const actualOutput = apiTokens.completion_tokens || botTokenCount;

        tokenStats.totalInput = tokenStats.totalInput - userTokenCount + actualInput;
        tokenStats.totalOutput += actualOutput;
        tokenStats.totalTokens = tokenStats.totalInput + tokenStats.totalOutput;
        tokenStats.botTokens += actualOutput;
        tokenStats.messageCount += 1;

        // Update model badge
        if (data.model) {
            document.getElementById('tokenModelBadge').textContent = data.model;
        }

        conversationMessages.push({
            role: 'assistant',
            content: reply
        });

        chatHistory.push({
            role: 'agent',
            content: reply,
            time: getCurrentTime()
        });

        saveTokenStats();
        updateTokenDisplay();
        saveChatHistory();
        scrollToBottom();

    } catch (error) {
        hideTyping();

        const errorMsg = createMessageElement(
            `❌ **Connection Error**: Gak bisa connect ke server.\n\n` +
            `Pastikan server udah jalan:\n\`python3 server.py\`\n\n` +
            `Error: ${error.message}`,
            'agent'
        );
        messagesContainer.appendChild(errorMsg);
        scrollToBottom();
    }
}

// Show/Hide Typing
function showTyping() {
    typingIndicator.classList.add('show');
    sendBtn.disabled = true;
    messageInput.disabled = true;
}

function hideTyping() {
    typingIndicator.classList.remove('show');
    sendBtn.disabled = false;
    messageInput.disabled = false;
    messageInput.focus();
}

// Scroll to Bottom
function scrollToBottom() {
    chatContainer.scrollTop = chatContainer.scrollHeight;
}

// New Chat
function newChat() {
    chatHistory = [];
    conversationMessages = [];
    currentChatId = Date.now().toString();
    messagesContainer.innerHTML = '';
    welcomeScreen.classList.remove('hidden');
}

// Clear Chat
function clearChat() {
    if (confirm('Yakin mau clear chat?')) {
        newChat();
    }
}

// Delete Chat
function deleteChat(event) {
    event.stopPropagation();
    newChat();
}

// Export Chat
function exportChat() {
    if (chatHistory.length === 0) {
        alert('Belum ada chat!');
        return;
    }

    let text = '# SOVEREIGN Chat Export\n\n';
    text += `**Token Stats:** ${formatNumber(tokenStats.totalTokens)} total\n\n`;
    chatHistory.forEach(msg => {
        const role = msg.role === 'user' ? '👤 Kamu' : '⚡ SOVEREIGN';
        text += `**${role}** (${msg.time}):\n${msg.content}\n\n---\n\n`;
    });

    const blob = new Blob([text], { type: 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `sovereign-chat-${new Date().toISOString().split('T')[0]}.md`;
