// Save Chat History
function saveChatHistory() {
    const allChats = JSON.parse(localStorage.getItem('sovereign_chats') || '[]');
    const chatIndex = allChats.findIndex(c => c.id === currentChatId);
    const chatData = {
        id: currentChatId,
        title: chatHistory[0]?.content.substring(0, 30) || 'Chat Baru',
        messages: chatHistory,
        conversation: conversationMessages,
        updatedAt: new Date().toISOString()
    };

    if (chatIndex >= 0) {
        allChats[chatIndex] = chatData;
    } else {
        allChats.unshift(chatData);
    }

    if (allChats.length > 20) allChats.pop();

    localStorage.setItem('sovereign_chats', JSON.stringify(allChats));
    updateHistorySidebar();
}

// Load Chat History
function loadChatHistory() {
    const allChats = JSON.parse(localStorage.getItem('sovereign_chats') || '[]');

    if (allChats.length > 0) {
        const recent = allChats[0];
        currentChatId = recent.id;
        chatHistory = recent.messages || [];
        conversationMessages = recent.conversation || [];

        chatHistory.forEach(msg => {
            const sender = msg.role === 'user' ? 'user' : 'agent';
            const msgEl = createMessageElement(msg.content, sender);
            messagesContainer.appendChild(msgEl);
        });

        if (chatHistory.length > 0) {
            welcomeScreen.classList.add('hidden');
        }
    }

    updateHistorySidebar();
}

// Update Sidebar History
function updateHistorySidebar() {
    const allChats = JSON.parse(localStorage.getItem('sovereign_chats') || '[]');
    const historyContainer = document.querySelector('.chat-history');

    historyContainer.innerHTML = allChats.map(chat => `
        <div class="history-item ${chat.id === currentChatId ? 'active' : ''}" 
             onclick="loadChat('${chat.id}')">
            <span class="history-icon">💬</span>
            <span class="history-text">${chat.title || 'Chat Baru'}</span>
            <button class="delete-btn" onclick="deleteSpecificChat(event, '${chat.id}')">✕</button>
        </div>
    `).join('');
}

// Load specific chat
function loadChat(chatId) {
    const allChats = JSON.parse(localStorage.getItem('sovereign_chats') || '[]');
    const chat = allChats.find(c => c.id === chatId);

    if (chat) {
        currentChatId = chat.id;
        chatHistory = chat.messages || [];
        conversationMessages = chat.conversation || [];

        messagesContainer.innerHTML = '';
        chatHistory.forEach(msg => {
            const sender = msg.role === 'user' ? 'user' : 'agent';
            const msgEl = createMessageElement(msg.content, sender);
            messagesContainer.appendChild(msgEl);
        });

        welcomeScreen.classList.add('hidden');
        updateHistorySidebar();
        scrollToBottom();
    }
}

// Delete specific chat
function deleteSpecificChat(event, chatId) {
    event.stopPropagation();
    let allChats = JSON.parse(localStorage.getItem('sovereign_chats') || '[]');
    allChats = allChats.filter(c => c.id !== chatId);
    localStorage.setItem('sovereign_chats', JSON.stringify(allChats));

    if (currentChatId === chatId) newChat();
    updateHistorySidebar();
}

