def switch_by_role(agent, role):
    p = custom_providers.get_by_role(role)
    if not p:
        print(f"{YELLOW}Belum ada endpoint dengan role '{role}'. Atur di: SOVEREIGN setup > Multi Custom Endpoint.{RESET}\n")
        return
    try:
        agent.set_provider(p["name"])
        agent.provider_name = p["name"]
        print(f"{GREEN}[provider diganti ke: {p['name']} (role={role})]{RESET}\n")
    except Exception as e:
        print(f"[error] {e}\n")


